INSERT INTO `article_drafts` VALUES (1,8,1,'Award-Winning Director Announces New Science Fiction FilmAward-Winning Director Announces New Science Fiction Film','The acclaimed filmmaker revealed plans for a new science fiction movie set to begin production later this year.','<p>Award-winning director Elena Brooks confirmed that her next project will be a large-scale science fiction film exploring the relationship between humans and artificial intelligence.</p><p>Production is expected to begin in late 2026, with casting announcements scheduled for the coming months.</p><p>Fans reacted positively on social media after the announcement, with many praising the director’s return to the genre that helped launch her career.</p><p>Studio executives believe the film could become one of the biggest releases of the year.</p>','articles/Mq1TzoTosRl40KGrgMlO4PRVWQLrDrU2nabqxOqK.jpg',NULL,'2026-05-16 12:02:45','2026-05-16 12:02:45'),(2,6,1,'Researchers Develop New Treatment Approach for Diabetes','Scientists say a new experimental treatment may improve blood sugar control for patients with Type 2 diabetes.','<p>Researchers at a leading medical institute have reported promising early results from a clinical trial involving a new diabetes treatment approach.</p><p>The therapy combines medication with personalized nutrition planning and digital monitoring tools to improve long-term blood sugar management.</p><p>Doctors involved in the study say patients experienced more stable glucose levels and fewer complications during the trial period.</p><p>Further testing is expected before the treatment becomes widely available to the public.</p>','articles/FUx2KuUf9gEiZvoyShK7v268Ae5c35K9RpbjgQYC.jpg',NULL,'2026-05-16 12:34:14','2026-05-16 12:34:14');
/*!40000 ALTER TABLE `article_drafts` ENABLE KEYS */;
UNLOCK TABLES;

