INSERT INTO `article_versions` VALUES (1,8,1,'Award-Winning Director Announces New Science Fiction FilmAward-Winning Director Announces New Science Fiction Film','The acclaimed filmmaker revealed plans for a new science fiction movie set to begin production later this year.','<p>Award-winning director Elena Brooks confirmed that her next project will be a large-scale science fiction film exploring the relationship between humans and artificial intelligence.</p><p>Production is expected to begin in late 2026, with casting announcements scheduled for the coming months.</p><p>Fans reacted positively on social media after the announcement, with many praising the director’s return to the genre that helped launch her career.</p><p>Studio executives believe the film could become one of the biggest releases of the year.</p>','articles/Ni5ccvkMyZiVeVVl1yssHVTRjRFMcU0fQYfDiqzt.jpg',NULL,1,'manual','2026-05-16 12:02:18','2026-05-16 12:02:18'),(2,8,2,'Award-Winning Director Announces New Science Fiction FilmAward-Winning Director Announces New Science Fiction Film','The acclaimed filmmaker revealed plans for a new science fiction movie set to begin production later this year.','<p>Award-winning director Elena Brooks confirmed that her next project will be a large-scale science fiction film exploring the relationship between humans and artificial intelligence.</p><p>Production is expected to begin in late 2026, with casting announcements scheduled for the coming months.</p><p>Fans reacted positively on social media after the announcement, with many praising the director’s return to the genre that helped launch her career.</p><p>Studio executives believe the film could become one of the biggest releases of the year.</p>','articles/Mq1TzoTosRl40KGrgMlO4PRVWQLrDrU2nabqxOqK.jpg',NULL,1,'manual','2026-05-16 12:02:43','2026-05-16 12:02:43'),(3,8,3,'Award-Winning Director Announces New Science Fiction FilmAward-Winning Director Announces New Science Fiction Film','The acclaimed filmmak