/*!40000 ALTER TABLE `articles` DISABLE KEYS */;
INSERT INTO `articles` VALUES (6,1,6,'Researchers Develop New Treatment Approach for Diabetes','researchers-develop-new-treatment-approach-for-diabetes','<p>Researchers at a leading medical institute have reported promising early results from a clinical trial involving a new diabetes treatment approach.</p><p>The therapy combines medication with personalized nutrition planning and digital monitoring tools to improve long-term blood sugar management.</p><p>Doctors involved in the study say patients experienced more stable glucose levels and fewer complications during the trial period.</p><p>Further testing is expected before the treatment becomes widely available to the public.</p>','Scientists say a new experimental treatment may improve blood sugar control for patients with Type 2 diabetes.','articles/FUx2KuUf9gEiZvoyShK7v268Ae5c35K9RpbjgQYC.jpg','published',0,0,'2026-05-16 03:09:00','2026-05-16 03:09:54','2026-05-16 12:34:17',NULL,NULL),(7,2,4,'Local Fashion Brand Expands Into International Markets','local-fashion-brand-expands-into-international-markets','<p>Popular clothing brand Urban Thread announced plans to expand internationally following strong domestic sales growth over the past two years.</p><p>The company intends to launch retail locations in Singapore, the United Arab Emirates, and the United Kingdom before the holiday shopping season.</p><p>Executives say online demand from overseas customers played a major role in the decision to expand globally.</p><p>Retail analysts note that regional fashion brands are increasingly finding success through social media-driven marketing strategies.</p>','The growing fashion company plans to open stores in three new countries by the end of the year.','articles/wHa70EEoIy1sX3ZoejCpJGlDtyfcEoN8WYz7Ymb4.jpg','published',0,0,'2026-05-16 04:55:00','2026-05-16 04:52:12','2026-05-16 12:33:49',NULL,NULL),(8,1,5,'Award-Winning Director Announces New Science Fiction Film','award-winning-director-announces-new-science-fiction-filmaward-winning-director-announces-new-science-fiction-film','<p>Award-winning director Elena Brooks confirmed that her next project will be a large-scale science fiction film exploring the relationship between humans and artificial intelligence.</p><p>Production is expected to begin in late 2026, with casting announcements scheduled for the coming months.</p><p>Fans reacted positively on social media after the announcement, with many praising the director’s return to the genre that helped launch her career.</p><p>Studio executives believe the film could become one of the biggest releases of the year.</p>','The acclaimed filmmaker revealed plans for a new science fiction movie set to begin production later this year.','articles/Mq1TzoTosRl40KGrgMlO4PRVWQLrDrU2nabqxOqK.jpg','published',1,1,'2026-05-16 12:02:00','2026-05-16 12:02:04','2026-05-16 12:35:29',NULL,NULL);
/*!40000 ALTER TABLE `articles` ENABLE KEYS */;
UNLOCK TABLES;

--
